`,paraId:12,tocIndex:8},{value:`// \u6CE8\u610F\uFF1Ajavascript \u4EE3\u7801\u7531 chatGPT\u{1F916} \u6839\u636E\u6211\u7684 java \u4EE3\u7801\u7FFB\u8BD1\uFF0C\u65E8\u5728\u5E2E\u52A9\u4E0D\u540C\u80CC\u666F\u7684\u8BFB\u8005\u7406\u89E3\u7B97\u6CD5\u903B\u8F91\u3002
// \u672C\u4EE3\u7801\u4E0D\u4FDD\u8BC1\u6B63\u786E\u6027\uFF0C\u4EC5\u4F9B\u53C2\u8003\u3002\u5982\u6709\u7591\u60D1\uFF0C\u53EF\u4EE5\u53C2\u7167\u6211\u5199\u7684 java \u4EE3\u7801\u5BF9\u6BD4\u67E5\u770B\u3002

const BFS = function (start, target) {
  const q = []; // \u6838\u5FC3\u6570\u636E\u7ED3\u6784
  const visited = new Set(); // \u907F\u514D\u8D70\u56DE\u5934\u8DEF
  const step = 0;

  q.push(start); // \u5C06\u8D77\u70B9\u52A0\u5165\u961F\u5217
  visited.add(start);

  while (q.length > 0) {
    const sz = q.length;
    /* \u5C06\u5F53\u524D\u961F\u5217\u4E2D\u7684\u6240\u6709\u8282\u70B9\u5411\u56DB\u5468\u6269\u6563 */
    for (const i = 0; i < sz; i++) {
      const cur = q.shift();
      /* \u5212\u91CD\u70B9\uFF1A\u8FD9\u91CC\u5224\u65AD\u662F\u5426\u5230\u8FBE\u7EC8\u70B9 */
      if (cur == target) return step;
      /* \u5C06 cur \u7684\u76F8\u90BB\u8282\u70B9\u52A0\u5165\u961F\u5217 */
      const adj = cur.adj();
      for (const j = 0; j < adj.length; j++) {
        const x = adj[j];
        if (!visited.has(x)) {
          q.push(x);
          visited.add(x);
        }
      }
    }
    step++;
  }
  // \u5982\u679C\u8D70\u5230\u8FD9\u91CC\uFF0C\u8BF4\u660E\u5728\u56FE\u4E2D\u6CA1\u6709\u627E\u5230\u76EE\u6807\u8282\u70B9
};
