type Partition = (head: ListNode | null, x: number) => ListNode | null;

export const partition: Partition = (head, x) => {
  // \u5B58\u653E\u5C0F\u4E8E x \u7684\u94FE\u8868\u7684\u865A\u62DF\u5934\u8282\u70B9
  const dummy1 = new ListNode(-1);
  // \u5B58\u653E\u5927\u4E8E\u7B49\u4E8E x \u7684\u94FE\u8868\u7684\u865A\u62DF\u5934\u8282\u70B9
  const dummy2 = new ListNode(-1);
  // p \u8D1F\u8D23\u904D\u5386\u539F\u94FE\u8868
  let p = head;
  // p1,p2 \u8D1F\u8D23\u751F\u6210\u7ED3\u679C\u94FE\u8868
  let p1 = dummy1;
  let p2 = dummy2;

  while (p != null) {
    if (p.val >= x) {
      p2.next = p;
      p2 = p2.next;
    } else {
      p1.next = p;
      p1 = p1.next;
    }

    // \u65AD\u5F00\u539F\u94FE\u8868\u4E2D\u7684\u6BCF\u4E2A\u8282\u70B9\u7684 next \u6307\u9488
    const temp = p.next;
    p.next = null;
    p = temp;
  }

  // \u8FDE\u63A5\u4E24\u4E2A\u94FE\u8868
  p1.next = dummy2.next;

  return dummy1.next;
};
