type Fib = (n: number) => number;

// \u81EA\u9876\u5411\u4E0B \u9012\u5F52\u6C42\u89E3
export const fib1: Fib = (n) => {
  // base case
  if (n === 1 || n === 2) return 1;

  return fib1(n - 1) + fib1(n - 2);
};

// \u81EA\u9876\u5411\u4E0B \u9012\u5F52\u6C42\u89E3
// \u5907\u5FD8\u5F55
export const fib2: Fib = (n) => db(Array(n + 1).fill(0), n);

const db: (memo: number[], n: number) => number = (memo, n) => {
  // base case
  if (n === 0 || n === 1) return n;

  // \u5DF2\u7ECF\u8BA1\u7B97\u8FC7\uFF0C\u4E0D\u8981\u518D\u8BA1\u7B97\u4E86
  if (memo[n] != 0) return memo[n];

  memo[n] = db(memo, n - 1) + db(memo, n - 2);

  return memo[n];
};

// \u81EA\u4F4E\u5411\u4E0A \u5FAA\u73AF\u8FED\u4EE3
// db \u6570\u7EC4\u7684\u8FED\u4EE3\u89E3\u6CD5
export const fib3: Fib = (n) => {
  if (n === 0) return 0;

  const dp = Array(n + 1).fill(0);

  // base case
  dp[0] = 0;
  dp[1] = 1;

  for (let i = 2; i <= n; i++) {
    // \u72B6\u6001\u8F6C\u79FB\u65B9\u7A0B
    dp[i] = dp[i - 1] + dp[i - 2];
  }

  return dp[n];
};

// \u4F18\u5316 db \u6570\u7EC4\u7684\u8FED\u4EE3\u89E3\u6CD5
export const fib4: Fib = (n) => {
  // base case
  if (n === 0 || n === 1) return n;

  let dp1 = 1,
    dp2 = 1;

  for (let i = 2; i <= n; i++) {
    // \u72B6\u6001\u8F6C\u79FB\u65B9\u7A0B
    const dp = dp1 + dp2;

    // \u6EDA\u52A8\u66F4\u65B0
    dp2 = dp1;
    dp1 = dp;
  }

  return dp1;
};
