type IsPalindrome = (s: string) => boolean;

export const isPalindrome: IsPalindrome = (s) => {
  // \u4E00\u5DE6\u4E00\u53F3\u4E24\u4E2A\u6307\u9488\u76F8\u5411\u800C\u884C
  let left = 0,
    right = s.length - 1;

  while (left < right) {
    if (s.charAt(left) !== s.charAt(right)) {
      return false;
    }

    left++;
    right--;
  }

  return true;
};
`},52523:function(o,u){"use strict";u.Z=`// \u6700\u957F\u56DE\u6587\u5B50\u4E32

type Palindrome = (s: string, l: number, r: number) => string;

// \u5728 s \u4E2D\u5BFB\u627E\u4EE5 s[l] \u548C s[r] \u4E3A\u4E2D\u5FC3\u7684\u6700\u957F\u56DE\u6587\u4E32
const palindrome: Palindrome = (s, l, r) => {
  while (l >= 0 && r < s.length && s.charAt(l) === s.charAt(r)) {
    l--;
    r++;
  }

  // \u8FD4\u56DE\u4EE5 s[l] \u548C s[r] \u4E3A\u4E2D\u5FC3\u7684\u6700\u957F\u56DE\u6587\u4E32
  return s.substring(l + 1, r);
};

type LongestPalindrome = (s: string) => string;

export const longestPalindrome: LongestPalindrome = (s) => {
  let res = '';

  for (let i = 0; i < s.length; i++) {
    const s1 = palindrome(s, i, i);
    const s2 = palindrome(s, i, i + 1);

    // res \u4E3A res s1 s2 \u4E2D\u6700\u5927\u503C
    res = res.length > s1.length ? res : s1;
    res = res.length > s2.length ? res : s2;
  }

  return res;
};
