type ReverseString = (s: string[]) => string[];

export const reverseString: ReverseString = (s) => {
  // \u4E00\u5DE6\u4E00\u53F3\u4E24\u4E2A\u6307\u9488\u76F8\u5411\u800C\u884C
  let left = 0,
    right = s.length - 1;

  while (left < right) {
    // \u4EA4\u6362 s[left] \u548C s[right]
    let temp = s[left];

    s[left] = s[right];
    s[right] = temp;

    left++;
    right--;
  }

  return s;
};
