type TwoSum = (nums: number[], target: number) => number[];

export const twoSum: TwoSum = (nums, target) => {
  let left = 0,
    right = nums.length - 1;

  while (left < right) {
    let sum = nums[left] + nums[right];

    if (sum === target) {
      // \u9898\u76EE\u7D22\u5F15\u662F\u4ECE 1 \u5F00\u59CB\u7684\uFF0C\u4E14\u53EA\u4F1A\u6709\u4E00\u4E2A\u7B54\u6848
      return [left + 1, right + 1];
    } else if (sum < target) {
      left++;
    } else if (sum > target) {
      right--;
    }
  }

  return [];
};
